"use client";

import React, { useState, useEffect } from "react";
import axios from "axios";
import DashboardLayout from "@/components/layout/DashboardLayout";
import CommandCenter from "@/components/CommandCenter";
import ScreenViewer from "@/components/ScreenViewer";
import IntelligencePanel from "@/components/IntelligencePanel";

const API_BASE_URL = "http://localhost:8000";

export default function Home() {
  const [taskId, setTaskId] = useState<string | null>(null);
  const [taskStatus, setTaskStatus] = useState<any>({
    status: "idle",
    logs: [],
    last_screenshot: null
  });
  const [chatHistory, setChatHistory] = useState<any[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  // Poll for task status
  useEffect(() => {
    let interval: any;
    if (taskId && (taskStatus.status === "running" || taskStatus.status === "starting" || taskStatus.status === "thinking" || taskStatus.status === "executing")) {
      interval = setInterval(async () => {
        try {
          const response = await axios.get(`${API_BASE_URL}/task/${taskId}`);
          
          let displayStatus = response.data.status;
          if (displayStatus === "running") {
            const lastLog = response.data.logs[response.data.logs.length - 1]?.toLowerCase() || "";
            if (lastLog.includes("thinking") || lastLog.includes("analyzing")) displayStatus = "thinking";
            else if (lastLog.includes("executing") || lastLog.includes("clicking") || lastLog.includes("typing")) displayStatus = "executing";
          }

          setTaskStatus({
            ...response.data,
            status: displayStatus === "running" ? "executing" : (displayStatus === "stopped" ? "failed" : displayStatus)
          });
          
          if (response.data.status === "completed" || response.data.status === "failed" || response.data.status === "stopped") {
            setIsProcessing(false);
            clearInterval(interval);
            
            // Add AI completion response to chat
            setChatHistory(prev => [...prev, { 
              role: "ai", 
              content: response.data.status === "completed" ? "Protocol successfully finalized." : "Task interrupted or failed." 
            }]);
          }
        } catch (error) {
          console.error("Error polling task:", error);
        }
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [taskId, taskStatus.status]);

  const handleSendCommand = async (command: string) => {
    setIsProcessing(true);
    setChatHistory(prev => [...prev, { role: "user", content: command }]);
    
    setTaskStatus({ 
      status: "thinking", 
      logs: ["Initializing neural bridge...", "Analyzing screen context..."], 
      last_screenshot: taskStatus.last_screenshot 
    });
    
    setTimeout(() => {
      setChatHistory(prev => [...prev, { role: "ai", content: "Understood. Accessing the interface now..." }]);
    }, 1000);

    try {
      const formData = new FormData();
      formData.append("command", command);
      
      const response = await axios.post(`${API_BASE_URL}/execute-task`, formData);
      setTaskId(response.data.task_id);
    } catch (error) {
      console.error("Error starting task:", error);
      setTaskStatus({ 
        status: "failed", 
        logs: ["ERR: Connection lost with backend engine."], 
        last_screenshot: null 
      });
      setIsProcessing(false);
    }
  };

  const handleStopTask = async () => {
    if (!taskId || !isProcessing) return;
    try {
      const formData = new FormData();
      formData.append("task_id", taskId);
      await axios.post(`${API_BASE_URL}/stop-task`, formData);
      setIsProcessing(false);
      setTaskStatus(prev => ({ ...prev, status: "idle" }));
    } catch (error) {
      console.error("Error stopping task:", error);
    }
  };

  return (
    <DashboardLayout status={taskStatus.status}>
      <div className="grid grid-cols-1 xl:grid-cols-[400px_1fr_400px] xl:h-[calc(100vh-80px)] overflow-y-auto xl:overflow-hidden">
        {/* Left: Command Console / Chat */}
        <div className="h-[600px] xl:h-full border-b xl:border-b-0 xl:border-r border-white/5">
          <CommandCenter 
            onSendCommand={handleSendCommand}
            onStopTask={handleStopTask}
            isProcessing={isProcessing}
            status={taskStatus.status}
            chatHistory={chatHistory}
          />
        </div>

        {/* Center: Live Preview */}
        <div className="h-[500px] xl:h-full border-b xl:border-b-0 border-white/5">
          <ScreenViewer 
            screenshot={taskStatus.last_screenshot}
            status={taskStatus.status}
          />
        </div>

        {/* Right: Agent Reasoning & Logs */}
        <div className="h-[500px] xl:h-full">
          <IntelligencePanel 
            logs={taskStatus.logs}
            status={taskStatus.status}
          />
        </div>
      </div>
    </DashboardLayout>
  );
}
